+fn span() -> SourceSpan {
+    SourceSpan::new(0, 0, 1, 1, 1, 1)
+}
+
+fn make_element(tag: &str) -> LoweredElement {
+    LoweredElement {
+        element_type: ElementType::Intrinsic {
+            tag: tag.to_string(),
+        },
+        props: LoweredProps {
+            entries: Vec::new(),
+            has_spreads: false,
+            extracted_key: None,
+            extracted_ref: None,
+        },
+        children: Vec::new(),
+        call_convention: CallConvention::Classic {
+            object: "React".into(),
+            method: "createElement".into(),
+        },
+        source_location: None,
+        is_static_children: false,
+        depth: 0,
+        span: span(),
+    }
+}
+
+fn make_component_element(name: &str) -> LoweredElement {
+    LoweredElement {
+        element_type: ElementType::Component {
+            name: name.to_string(),
+        },
+        props: LoweredProps {
+            entries: Vec::new(),
+            has_spreads: false,
+            extracted_key: None,
+            extracted_ref: None,
+        },
+        children: Vec::new(),
+        call_convention: CallConvention::Classic {
+            object: "React".into(),
+            method: "createElement".into(),
+        },
+        source_location: None,
+        is_static_children: false,
+        depth: 0,
+        span: span(),
+    }
+}
+
+fn make_element_with_props(tag: &str, props: Vec<(&str, LoweredPropValue)>) -> LoweredElement {
+    let entries = props
+        .into_iter()
+        .map(|(name, value)| {
+            PropsEntry::Named(LoweredProp {
+                name: name.to_string(),
+                value,
+                span: None,
+            })
+        })
+        .collect();
+    LoweredElement {
+        element_type: ElementType::Intrinsic {
+            tag: tag.to_string(),
+        },
+        props: LoweredProps {
+            entries,
+            has_spreads: false,
+            extracted_key: None,
+            extracted_ref: None,
+        },
+        children: Vec::new(),
+        call_convention: CallConvention::Classic {
+            object: "React".into(),
+            method: "createElement".into(),
+        },
+        source_location: None,
+        is_static_children: false,
+        depth: 0,
+        span: span(),
+    }
+}
+
+fn make_nested_element(depth: usize) -> LoweredElement {
+    let mut el = make_element("span");
+    for _ in 0..depth {
+        let wrapper = LoweredElement {
+            children: vec![LoweredChild::Element(Box::new(el))],
+            ..make_element("div")
+        };
+        el = wrapper;
+    }
+    el
+}
+
+fn make_hook_manifest(name: &str, hooks: Vec<HookKind>) -> HookManifest {
+    let slots = hooks
+        .into_iter()
+        .enumerate()
+        .map(|(i, kind)| HookSlot {
+            index: HookSlotIndex(i as u32),
+            kind,
+            deps: None,
+        })
+        .collect();
+    HookManifest::new(name, slots)
+}
+
+fn make_element_with_children(tag: &str, children: Vec<LoweredElement>) -> LoweredElement {
+    LoweredElement {
+        children: children
+            .into_iter()
+            .map(|c| LoweredChild::Element(Box::new(c)))
+            .collect(),
+        ..make_element(tag)
+    }
+}
