+    PathEvidence {
+        path_id: path_id.to_string(),
+        execution_kind: kind,
+        mode,
+        hash: ContentHash::compute(content),
+        epoch: epoch(),
+        duration_micros: 500,
+        output_size_bytes: content.len() as u64,
+    }
