+            for strat in SpecializationStrategy::ALL {
+                let b = compute_specialization_benefit(*shape, *strat);
+                assert!(b >= 1_000_000, "{lane}+{shape}+{strat} => {b} < 1_000_000");
+            }
+        }
+    }
